## 데이터 타입
```ts
type MedForm = 'oral' | 'injection' | 'other';
type FreqType = 'daily' | 'weekly';
type TimeSlot = 'morning' | 'lunch' | 'evening' | 'bedtime';
type MealCondition = 'fasting' | 'before' | 'after' | 'any';
type LogStatus = 'taken' | 'missed' | 'pending';

interface MedSchedule { id: string; timeSlot: TimeSlot; timeDetail: string; }
interface Medication {
  id: string; name: string; form: MedForm; dosage: string;
  frequency: FreqType; frequencyDays: string[];
  schedules: MedSchedule[];
  condition: MealCondition; memo: string;
  colorIndex: number; isActive: boolean; createdAt: string;
}
interface MedLog {
  id: string; medicationId: string; scheduleId: string;
  date: string; status: LogStatus; checkedAt: string | null;
}
interface CheckItem {
  medicationId: string; scheduleId: string; name: string;
  dosage: string; condition: MealCondition;
  timeSlot: TimeSlot; timeDetail: string;
  color: string; log: MedLog | null;
}
```

